def gen(rng, size):
    n = max(1, min(size, 2000))
    half = n // 2
    counts = [0] * 26
    for _ in range(half):
        counts[rng.randint(0, 25)] += 1
    pool = []
    for i in range(26):
        pool.extend([chr(97 + i)] * (counts[i] * 2))
    if n % 2 == 1:
        pool.append(chr(97 + rng.randint(0, 25)))
    rng.shuffle(pool)
    return [''.join(pool)]

