class Solution:
    def minMovesToMakePalindrome(self, s):
        chs = list(s)
        moves = 0
        lo, hi = 0, len(chs) - 1
        while lo < hi:
            if chs[lo] == chs[hi]:
                lo += 1
                hi -= 1
                continue
            k = lo
            while k < hi and chs[k] != chs[hi]:
                k += 1
            if k == hi:
                chs[lo], chs[lo + 1] = chs[lo + 1], chs[lo]
                moves += 1
                continue
            for m in range(k, lo, -1):
                chs[m], chs[m - 1] = chs[m - 1], chs[m]
                moves += 1
            lo += 1
            hi -= 1
        return moves

