class Solution:
    def minMovesToMakePalindrome(self, s):
        chs = list(s)
        moves = 0
        i, j = 0, len(chs) - 1
        while i < j:
            k = j
            while k > i and chs[k] != chs[i]:
                k -= 1
            if k == i:
                chs[i], chs[i + 1] = chs[i + 1], chs[i]
                moves += 1
                continue
            for m in range(k, j):
                chs[m], chs[m + 1] = chs[m + 1], chs[m]
                moves += 1
            i += 1
            j -= 1
        return moves

