var minMovesToMakePalindrome = function(s) {
    const arr = s.split('');
    let moves = 0;
    let i = 0, j = arr.length - 1;
    while (i < j) {
        let k = j;
        while (k > i && arr[k] !== arr[i]) k--;
        if (k === i) {
            const tmp = arr[i]; arr[i] = arr[i + 1]; arr[i + 1] = tmp;
            moves++;
            continue;
        }
        for (let m = k; m < j; m++) {
            const tmp = arr[m]; arr[m] = arr[m + 1]; arr[m + 1] = tmp;
            moves++;
        }
        i++;
        j--;
    }
    return moves;
};
